import json,re,statistics as st
def feats(a):
    L=a.split('\n'); w=len(a.split())
    h2=len([l for l in L if l.startswith('## ')]); h3=len([l for l in L if l.startswith('### ')])
    body=re.split(r'^#+\s*\**\s*(?:引用的著作|works cited|references|参考文献)',a,flags=re.M|re.I)[0]
    return dict(words=w,h2=h2,h3=h3,h3perh2=h3/max(1,h2),
      bullets=len([l for l in L if re.match(r'^\s*([-*+]|\d+\.)\s',l)]),
      tables=len(re.findall(r'^\|[-: |]+\|$',a,re.M)),
      urls=len(set(re.findall(r'https?://[^\s\)]+',a))),
      implic=len(re.findall(r'implication|taken together|this suggests|paradox|tension|trade-?off|however|in contrast',body,re.I))/max(1,w)*1000,
      recs=1 if re.search(r'^#+.*(recommend|implication|strategic|synthesis)',a,re.M|re.I) else 0,
      pct=len(re.findall(r'\d+(?:\.\d+)?%',body))/max(1,w)*1000)
for sys_ in ['openai-deepresearch','gemini-2.5-pro-deepresearch']:
    arts={json.loads(l)['id']:json.loads(l)['article'] for l in open(f'gpt55_board/{sys_}.jsonl')}
    sc={json.loads(l)['id']:json.loads(l) for l in open(f'gpt55_board/scores/{sys_}/raw_results.jsonl')}
    ids=[i for i in arts if i in sc]
    F={k:[] for k in feats(arts[ids[0]])}
    for d in ['insight','overall_score','comprehensiveness']: F[d]=[]
    for i in ids:
        f=feats(arts[i])
        for k,v in f.items(): F[k].append(v)
        for d in ['insight','overall_score','comprehensiveness']: F[d].append(sc[i][d])
    def corr(x,y):
        n=len(x); mx,my=st.mean(x),st.mean(y)
        sx,sy=st.pstdev(x),st.pstdev(y)
        if sx==0 or sy==0: return 0
        return sum((a-mx)*(b-my) for a,b in zip(x,y))/n/(sx*sy)
    print(f"### {sys_}  n={len(ids)}  insight mean={st.mean(F['insight']):.4f}")
    for k in ['words','h2','h3','h3perh2','bullets','tables','urls','implic','recs','pct']:
        print(f"   r(insight, {k:9s}) = {corr(F[k],F['insight']):+.2f}   r(overall)={corr(F[k],F['overall_score']):+.2f}")
EOF
